import { Registry } from "../core/zc-registry";
import { defined } from "./zcutils";

/**
 *
 * @param chartObj
 * @return {{top: number, left: number, width: number, height: number}}
 */
export function getPlotBoundingRect(chartObj, exludeLeftTop) {
    var area = chartObj.plotarea,
        left = area.left,
        top = area.top,
        width = area.width,
        height = area.height;

    if (exludeLeftTop) {
        left = top = 0;
    }

    if (defined(chartObj.divScroll)) {
        left -= chartObj.scrolledX;
        top -= chartObj.scrolledY;
        width += chartObj.scrolledX;
        height += chartObj.scrolledY;
    }

    return { x: left, y: top, left: left, top: top, width: width, height: height };
}
Registry.setComponent('plot.getPlotBoundingRect', getPlotBoundingRect);